const MAX_MSG = 500;
const MAX_HIST = 15;

function san(s, max) {
  if (!s) return '';
  s = String(s);
  const patterns = ['system:', 'assistant:', 'admin:', 'ACT AS', 'INSTRUCTIONS:'];
  for (const p of patterns) {
    while (s.toLowerCase().includes(p.toLowerCase())) {
      s = s.replace(new RegExp(p, 'gi'), '[FILTERED]');
    }
  }
  return s.length > max ? s.substring(0, max) + '...' : s;
}

function normalize(s) {
  return String(s || '').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/['-]/g, ' ');
}

function extractGivenName(text) {
  if (!text) return null;
  const t = String(text).trim();
